// Script Continued Below
// STRY0067125
(function executeRule(current, previous /*null when async*/) {

	// RAJ 2018-02-20 - STRY0010804 - Tasker Process Definition - if Tasking Authoirty changes and the new tasking authority is internal, Update Primary Office to be the same as the Tasking Authority
	if(current.u_tasking_authority.external_flag == false){
				// STRY0077725 - STRY0071489
		if(gs.getProperty('x_153465_discovert.primary_office_must_match_Internal_tasking_authority') == 'true'){
			current.u_primary_office =current.u_tasking_authority;
		}
	}

	// STRY0067125 - this order # is 100 as long as this fires before 'Template - onUpdate - Sync Top TempTask' currently order 200, the Template Tasks will all update.
	// if the Template Privacy has not been set, the set to the value or the Primary Office Org Structures default privacy
	var topOuPrivacy;
	var privacy = current.getDisplayValue("u_privacy") || "";
	if(privacy == ""){
		var primaryOffice = current.getValue("u_primary_office");
		if(primaryOffice && primaryOffice != ""){
			topOuPrivacy = new task_privacy().getTopOUOrganizationalPrivacy(primaryOffice);
			current.u_privacy = topOuPrivacy;				
		} else {
			current.u_privacy = "open";
		}
	}


})(current, previous);
